# Disassemble Manual vs GridCodec implementations
#
# This script compiles both implementations to .beam files and
# disassembles them to compare the generated bytecode.

output_dir = "artifacts/bytecode_analysis"
File.mkdir_p!(output_dir)

IO.puts(String.duplicate("=", 70))
IO.puts("MANUAL vs GRIDCODEC BYTECODE COMPARISON")
IO.puts(String.duplicate("=", 70))

# =============================================================================
# Write source files and compile to .beam
# =============================================================================

IO.puts("\nStep 1: Writing and compiling source files...")

# Manual pattern-match version
manual_source = ~S"""
defmodule Manual.SimpleCodec do
  @u64_null 18_446_744_073_709_551_615
  @u32_null 4_294_967_295
  @bool_null 255

  def encode(%{id: id, count: count, flag: flag}) do
    id_val = id || @u64_null
    count_val = count || @u32_null
    flag_byte = case flag do
      true -> 1
      false -> 0
      _ -> @bool_null
    end
    <<id_val::little-64, count_val::little-32, flag_byte::8>>
  end

  def decode(<<id::little-64, count::little-32, flag_byte::8>>) do
    id_val = if id == @u64_null, do: nil, else: id
    count_val = if count == @u32_null, do: nil, else: count
    flag_val = case flag_byte do
      0 -> false
      @bool_null -> nil
      _ -> true
    end
    {:ok, %{id: id_val, count: count_val, flag: flag_val}}
  end
end
"""

# Manual :maps.get version (mirrors what GridCodec does)
maps_get_source = ~S"""
defmodule Manual.MapsGetCodec do
  @u64_null 18_446_744_073_709_551_615
  @u32_null 4_294_967_295
  @bool_null 255

  def encode(data) do
    id_val = case :maps.get(:id, data, @u64_null) do
      nil -> @u64_null
      v -> v
    end
    count_val = case :maps.get(:count, data, @u32_null) do
      nil -> @u32_null
      v -> v
    end
    flag_byte = case :maps.get(:flag, data, @bool_null) do
      true -> 1
      false -> 0
      _ -> @bool_null
    end
    <<id_val::little-64, count_val::little-32, flag_byte::8>>
  end
end
"""

# GridCodec version
gridcodec_source = """
defmodule Generated.SimpleCodec do
  use GridCodec

  defcodec do
    field(:id, :u64)
    field(:count, :u32)
    field(:flag, :bool)
  end
end
"""

# Write source files
manual_path = Path.join(output_dir, "manual_codec.ex")
maps_get_path = Path.join(output_dir, "maps_get_codec.ex")
gridcodec_path = Path.join(output_dir, "gridcodec_codec.ex")

File.write!(manual_path, manual_source)
File.write!(maps_get_path, maps_get_source)
File.write!(gridcodec_path, gridcodec_source)

IO.puts("  Written: #{manual_path}")
IO.puts("  Written: #{maps_get_path}")
IO.puts("  Written: #{gridcodec_path}")

# Compile and get beam binaries
IO.puts("\nCompiling...")

[{Manual.SimpleCodec, manual_beam}] = Code.compile_string(manual_source)
[{Manual.MapsGetCodec, maps_get_beam}] = Code.compile_string(maps_get_source)
[{Generated.SimpleCodec, gridcodec_beam}] = Code.compile_string(gridcodec_source)

# Write beam files
manual_beam_path = Path.join(output_dir, "Elixir.Manual.SimpleCodec.beam")
maps_get_beam_path = Path.join(output_dir, "Elixir.Manual.MapsGetCodec.beam")
gridcodec_beam_path = Path.join(output_dir, "Elixir.Generated.SimpleCodec.beam")

File.write!(manual_beam_path, manual_beam)
File.write!(maps_get_beam_path, maps_get_beam)
File.write!(gridcodec_beam_path, gridcodec_beam)

IO.puts("  Compiled: #{manual_beam_path} (#{byte_size(manual_beam)} bytes)")
IO.puts("  Compiled: #{maps_get_beam_path} (#{byte_size(maps_get_beam)} bytes)")
IO.puts("  Compiled: #{gridcodec_beam_path} (#{byte_size(gridcodec_beam)} bytes)")

# =============================================================================
# Verify correctness
# =============================================================================

IO.puts("\n" <> String.duplicate("-", 70))
IO.puts("Step 2: VERIFY CORRECTNESS")
IO.puts(String.duplicate("-", 70))

test_data = %{id: 12345, count: 100, flag: true}
test_nil = %{id: nil, count: nil, flag: nil}
test_zero = %{id: 0, count: 0, flag: false}

for {label, data} <- [{"normal", test_data}, {"nil", test_nil}, {"zero/false", test_zero}] do
  manual = Manual.SimpleCodec.encode(data)
  maps_get = Manual.MapsGetCodec.encode(data)
  gridcodec = Generated.SimpleCodec.encode(data)

  IO.puts("\n  #{label}: #{inspect(data)}")
  IO.puts("    Manual:    #{inspect(manual)}")
  IO.puts("    MapsGet:   #{inspect(maps_get)}")
  IO.puts("    GridCodec: #{inspect(gridcodec)}")
  IO.puts("    All match: #{manual == maps_get and maps_get == gridcodec}")
end

# =============================================================================
# Disassemble
# =============================================================================

IO.puts("\n" <> String.duplicate("-", 70))
IO.puts("Step 3: DISASSEMBLE ENCODE FUNCTIONS")
IO.puts(String.duplicate("-", 70))

defmodule Disassembler do
  def disassemble(beam_path, function, arity) do
    case :beam_disasm.file(String.to_charlist(beam_path)) do
      {:beam_file, mod, _exports, _attrs, _compile_info, code} ->
        fn_code = Enum.find(code, fn
          {:function, ^function, ^arity, _, _} -> true
          _ -> false
        end)

        case fn_code do
          {:function, _, _, entry, instructions} ->
            {:ok, mod, entry, instructions}

          nil ->
            {:error, :function_not_found}
        end

      {:error, _, reason} ->
        {:error, reason}
    end
  end

  def format_instruction(instr) do
    case instr do
      {:label, n} -> "LABEL #{n}"
      {:func_info, _mod, {:atom, fun}, arity} -> "FUNC_INFO #{fun}/#{arity}"
      {:func_info, _mod, fun, arity} -> "FUNC_INFO #{inspect(fun)}/#{arity}"
      {:allocate, n, live} -> "ALLOCATE #{n} live=#{live}"
      {:deallocate, n} -> "DEALLOCATE #{n}"
      {:move, src, dst} -> "MOVE #{fmt(src)} -> #{fmt(dst)}"
      {:test, op, fail, args} -> "TEST #{op} #{fmt(fail)} #{fmt(args)}"
      {:call_ext, arity, mfa} -> "CALL_EXT/#{arity} #{fmt(mfa)}"
      {:select_val, src, fail, list} -> "SELECT_VAL #{fmt(src)} #{fmt(fail)}"
      {:jump, label} -> "JUMP #{fmt(label)}"
      {:get_map_elements, fail, src, {:list, pairs}} -> "GET_MAP_ELEMENTS #{fmt(fail)} #{fmt(src)} #{div(length(pairs), 2)} fields"
      {:get_map_elements, fail, src, pairs} -> "GET_MAP_ELEMENTS #{fmt(fail)} #{fmt(src)} #{inspect(pairs)}"
      {:bs_create_bin, _fail, _, _, _, _dst, {:list, segments}} -> "BS_CREATE_BIN #{div(length(segments), 6)} segments"
      {:bs_create_bin, _fail, _, _, _, _dst, segments} -> "BS_CREATE_BIN segments=#{inspect(segments, limit: 10)}"
      {:bs_match, _fail, _ctx, {:commands, cmds}} -> "BS_MATCH #{length(cmds)} cmds"
      {:bs_match, _fail, _ctx, cmds} -> "BS_MATCH #{inspect(cmds)}"
      {:put_map_assoc, _fail, _src, _dst, n, {:list, pairs}} -> "PUT_MAP_ASSOC #{div(length(pairs), 2)} fields"
      {:put_map_assoc, _fail, _src, _dst, n, _pairs} -> "PUT_MAP_ASSOC size=#{n}"
      {:line, _} -> "LINE"
      :return -> "RETURN"
      {:init_yregs, {:list, regs}} -> "INIT_YREGS #{length(regs)}"
      {:init_yregs, regs} -> "INIT_YREGS #{inspect(regs)}"
      {:badmatch, _} -> "BADMATCH"
      other -> "#{elem(other, 0)}"
    end
  end

  defp fmt({:f, n}), do: "f#{n}"
  defp fmt({:x, n}), do: "X#{n}"
  defp fmt({:y, n}), do: "Y#{n}"
  defp fmt({:atom, a}), do: ":#{a}"
  defp fmt({:integer, n}), do: "#{n}"
  defp fmt({:literal, v}), do: "lit"
  defp fmt({:extfunc, m, f, a}), do: "#{m}.#{f}/#{a}"
  defp fmt({:list, _}), do: "[...]"
  defp fmt({:tr, reg, _type}), do: fmt(reg)
  defp fmt(other), do: "?"

  def instruction_type(instr) do
    case instr do
      {op, _} -> op
      {op, _, _} -> op
      {op, _, _, _} -> op
      {op, _, _, _, _} -> op
      {op, _, _, _, _, _} -> op
      {op, _, _, _, _, _, _} -> op
      op when is_atom(op) -> op
      _ -> :other
    end
  end
end

# Disassemble all three encode functions
for {name, path} <- [
  {"Manual (pattern match)", manual_beam_path},
  {"Manual (:maps.get)", maps_get_beam_path},
  {"GridCodec", gridcodec_beam_path}
] do
  IO.puts("\n  #{name}:")

  case Disassembler.disassemble(path, :encode, 1) do
    {:ok, _mod, entry, instructions} ->
      IO.puts("    Entry: #{entry}, Instructions: #{length(instructions)}")

      # Count instruction types
      counts = instructions
        |> Enum.map(&Disassembler.instruction_type/1)
        |> Enum.frequencies()

      # Show key metrics
      call_ext = Map.get(counts, :call_ext, 0)
      get_map = Map.get(counts, :get_map_elements, 0)
      bs_create = Map.get(counts, :bs_create_bin, 0)
      moves = Map.get(counts, :move, 0)
      tests = Map.get(counts, :test, 0)

      IO.puts("    call_ext: #{call_ext}, get_map_elements: #{get_map}, bs_create_bin: #{bs_create}")
      IO.puts("    moves: #{moves}, tests: #{tests}")

      # Show instruction flow
      IO.puts("    Flow:")
      instructions
      |> Enum.reject(fn i -> match?({:line, _}, i) end)
      |> Enum.take(25)
      |> Enum.each(fn instr ->
        IO.puts("      #{Disassembler.format_instruction(instr)}")
      end)

      # Save full disassembly
      content = instructions
        |> Enum.map(&inspect(&1, pretty: true, limit: :infinity))
        |> Enum.join("\n")
      output_file = Path.join(output_dir, "#{String.replace(name, ~r/[^a-z0-9]/i, "_")}_encode.txt")
      File.write!(output_file, content)
      IO.puts("    Full disassembly saved to: #{output_file}")

    {:error, reason} ->
      IO.puts("    ERROR: #{inspect(reason)}")
  end
end

# =============================================================================
# Benchmark
# =============================================================================

IO.puts("\n" <> String.duplicate("-", 70))
IO.puts("Step 4: MICRO-BENCHMARK")
IO.puts(String.duplicate("-", 70))

iterations = 1_000_000
test_data = %{id: 12345, count: 100, flag: true}

IO.puts("\nEncoding #{iterations} iterations:")

{manual_time, _} = :timer.tc(fn ->
  for _ <- 1..iterations, do: Manual.SimpleCodec.encode(test_data)
end)

{maps_get_time, _} = :timer.tc(fn ->
  for _ <- 1..iterations, do: Manual.MapsGetCodec.encode(test_data)
end)

{gridcodec_time, _} = :timer.tc(fn ->
  for _ <- 1..iterations, do: Generated.SimpleCodec.encode(test_data)
end)

IO.puts("  Manual (pattern match):  #{Float.round(manual_time / 1000, 1)} ms")
IO.puts("  Manual (:maps.get):      #{Float.round(maps_get_time / 1000, 1)} ms")
IO.puts("  GridCodec:               #{Float.round(gridcodec_time / 1000, 1)} ms")
IO.puts("")
IO.puts("  GridCodec vs Pattern:    #{Float.round(gridcodec_time / manual_time, 2)}x")
IO.puts("  GridCodec vs MapsGet:    #{Float.round(gridcodec_time / maps_get_time, 2)}x")
IO.puts("  MapsGet vs Pattern:      #{Float.round(maps_get_time / manual_time, 2)}x")

# =============================================================================
# Key Insights
# =============================================================================

IO.puts("\n" <> String.duplicate("=", 70))
IO.puts("KEY INSIGHTS")
IO.puts(String.duplicate("=", 70))

IO.puts("""

The bytecode comparison reveals:

1. MANUAL PATTERN MATCH (optimal baseline)
   - Uses get_map_elements: Extracts all 3 fields in ONE instruction
   - No external function calls for map access
   - Direct binary construction

2. MANUAL :MAPS.GET (what GridCodec currently does)
   - Uses 3x call_ext to :maps.get/3
   - Each call has overhead: setup registers, call, return
   - This is the bottleneck!

3. GRIDCODEC (generated)
   - Same as #2: 3x call_ext to :maps.get/3
   - Plus additional case statements for nil handling

OPTIMIZATION PATH:
=================
To match Manual pattern match performance, GridCodec should:

Option A: Use get_map_elements (fast path)
  - Generate: %{id: id, count: count, flag: flag} = data
  - This extracts all fields in ONE instruction
  - Only works when all keys are expected to be present

Option B: Restructure encode AST generation
  - Extract values BEFORE binary construction
  - Reduces instruction interleaving
  - Already explored: ~10% improvement

Option C: Accept struct input (fastest)
  - If input is a struct, field access is just tuple element access
  - Eliminates map lookup entirely
""")
